#include <iostream>
using namespace std;

class Account {
private:
    double balance;
public:
    void deposit(double amount) {
        if (amount > 0) balance += amount;
    }
    double getBalance() {
        return balance;
    }
};

void setBalance(double b) {
    if (b >= 0) {
        balance = b;
    } else {
        cout << "Invalid balance!" << endl;
    }
}

#include <iostream>
using namespace std;

class Bank {
public:
    virtual float getInterestRate() = 0;
};

class SBI : public Bank {
public:
    float getInterestRate() { return 7.0; }
};

class ICICI : public Bank {
public:
    float getInterestRate() { return 8.5; }
};

int main() {
    SBI s;
    cout << "SBI: " << s.getInterestRate() << "%";
    return 0;
}

class Playable {
public:
    virtual void play() = 0; // Pure virtual function
    virtual ~Playable() {} // Virtual destructor
};

#include <iostream>
using namespace std;

class Account {
private:
    int balance = 1000;
    friend void showBalance(Account a);
};

void showBalance(Account a) {
    cout << "Balance: " << a.balance << endl; // Allowed
}

int main() {
    Account acc;
    showBalance(acc);
    return 0;
}

class Account {
    int balance;
    friend class Admin;
};

class Admin {
public:
    void reset(Account &a) { a.balance = 0; }
};

